public class CastDemo {
    public static void main(String[] args) {
        double d = 9.99;
        int i = (int) d;
        System.out.println(i);
        int x = 5;
        double result = x / 2;
        System.out.println(result);
        double result2 = (double) x / 2;
        System.out.println(result2);
    }
